WITH mediateChargeInfoAvailable AS ( SELECT DISTINCT /*+ INDEX(MEDIATE_CHARGE_INFO MEDIATE_CHARGE_INFO_IN1) */ MCI.BROKER_CODE , CASE B.CNT WHEN 1 THEN MCI.BROKER_BRANCH_CODE ELSE '' END AS BROKER_BRANCH_CODE , CASE B.CNT WHEN 1 THEN MB.BRANCH_NAME ELSE '' END AS BRANCH_NAME , MCI.BROKER_CHARGE_CODE , CASE MCI.BROKER_CHARGE_CODE WHEN '0000' THEN '' ELSE MCI.BROKER_CHARGE_NAME END AS BROKER_CHARGE_NAME FROM MEDIATE_CHARGE_INFO MCI INNER JOIN ( SELECT BROKER_CODE , BROKER_CHARGE_CODE , COUNT(*) CNT FROM MEDIATE_CHARGE_INFO WHERE DELETE_FLG = '0' GROUP BY BROKER_CODE , BROKER_CHARGE_CODE ) B ON MCI.BROKER_CODE = B.BROKER_CODE AND MCI.BROKER_CHARGE_CODE = B.BROKER_CHARGE_CODE LEFT OUTER JOIN MEDIATE_BRANCH MB ON MCI.BROKER_CODE = MB.BROKER_CODE AND MCI.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE WHERE MCI.DELETE_FLG = '0' GROUP BY MCI.BROKER_CODE , MCI.BROKER_BRANCH_CODE , MB.BRANCH_NAME , MCI.BROKER_CHARGE_CODE , BROKER_CHARGE_NAME , B.CNT ) SELECT /* @SQLID=SUB020302_0101-01#Sql001 */ COUNT(*) OVER() AS totalCount, A.BUTEN_CODE AS butenCode, A.ACCOUNT_NUMBER AS accountNumber, B.CUSTOMER_ATTRIBUTE AS customerAttribute, B.NAME_KANJI AS customerNameKanji, B.NAME_KANA AS customerNameKana, A.ORDER_NUM AS ecOrderNo, A.BRAND_CD AS brandCode, C.BRAND_NAME AS brandName, A.MARKET AS market, A.ORDER_STATUS AS orderStatus, A.TRADE_KBN AS tradeCd, A.ORDER_SYUBETSU_LIST AS orderClassList, A.AZUKARI_KBN AS depositType, A.PAYMENT_LIMIT AS paymentDeadline, A.COM_ID_R AS comIdR, A.ACCEPT_DATE AS orderDate, A.ACCEPT_TIME AS orderDayTimeCalculation, A."LIMIT" AS yukoKigen, A.QUANTITY AS quantity, A.AUTO_ORDER_KIND AS autoOrderKind, A.RBE_ORDER_KIND AS rbeOrderKind, A.RBE_ORDER_STATUS AS rbeOrderStatus, A.SASINARI_KBN AS sasinariKbn, A.PRICE AS price, A.TRIGGER_ZONE AS triggerZone, A.TRIGGER_PRICE AS triggerPrice, A.OCO_SASINARI_KBN AS ocoSasinariKbn, A.OCO_SASHINE AS ocoSashine, A.DONE_RBE_ORDER_KIND AS doneRbeOrderKind, A.DONE_SASINARI_KBN AS doneSasinariKbn, A.DONE_SASHINE AS doneSashine, A.DONE_TRIGGER_ZONE AS doneTriggerZone, A.DONE_TRIGGER_NEDAN AS doneTriggerPrice, A.DONE_OCO_SASINARI_KBN AS doneOcoSasinariKbn, A.DONE_OCO_SASHINE AS doneOcoSashine, A.DONE_LIMIT AS doneLimit, A.KANYU_KBN AS kanyuKbn, A.JUTYU_KBN AS orderMethod, A.DAILY_CREDIT_KBN AS dailyCreditKbn, A.PAYMENT_LIMIT_DATE AS paymentDeadlineDate, A.DATE_KBN AS dateKbn, H.USER_NM AS userName, A.BROKER_CODE AS brokerCode, D.BRANCH_NAME AS brokerName, E.BROKER_BRANCH_CODE AS brokerageBranchCode, E.BRANCH_NAME AS brokerBranchName, A.INTERMEDIARY_EMP_CD AS brokerChargeCode, E.BROKER_CHARGE_NAME AS employeeName, G.VISIBLE_BUTEN_CODE AS viewAblrButenCode, A.ACCEPT_LIMIT AS acceptLimit FROM T_JP_ORDER A INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO B ON A.BUTEN_CODE = B.BUTEN_CODE AND A.ACCOUNT_NUMBER = B.ACCOUNT_NUMBER AND ( (TRIM(A.SHUBETU) IS NULL AND A.SHUBETU IS NOT NULL) OR (TRIM(A.SHUBETU) = 'APL' AND A.CODE LIKE 'W%') ) LEFT JOIN STAR_BRAND_MASTER C ON SUBSTR(A.BRAND_CD, '0', '4') = SUBSTR(C.COMPANY_CD, '-4') AND SUBSTR(A.BRAND_CD, '-1') = C.NEW_OLD_CLASSIFY AND C.PRODUCT_CLASSIFY = 'K' AND C.DOMESTIC_FOREIGN_CLASSIFY = '0' AND C.RIGHT_CLASSIFY = ' ' LEFT JOIN MEDIATE_BRANCH D ON A.BROKER_CODE = D.BROKER_CODE AND D.BROKER_BRANCH_KIND = '00' AND D.DELETE_FLG = '0' LEFT JOIN mediateChargeInfoAvailable E ON A.BROKER_CODE = E.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = E.BROKER_CHARGE_CODE LEFT JOIN SUB_DEALER_CODE_RELATION_IFAP G ON A.BUTEN_CODE = G.BUTEN_CODE AND A.ACCOUNT_NUMBER = G.ACCOUNT_NUMBER LEFT JOIN TB_MED_USERS H ON A.CREATE_USER = H.USER_ID
AND 1 = 1
AND (A.BROKER_CODE IN
) OR A.BROKER_CODE IN (
,
#{brokerCharge.brokerCode}
)
AND ((A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN
) OR (A.BROKER_CODE, A.INTERMEDIARY_EMP_CD) IN (
,
(#{brokerCharge.brokerCode}, #{brokerCharge.empCode})
)
AND A.BROKER_CODE IN
#{brokerCode}
AND A.BROKER_CODE NOT IN
#{brokerCode}
AND E.BROKER_BRANCH_CODE = #{req.branchCode}
AND A.INTERMEDIARY_EMP_CD = #{req.empCode}
AND A.BUTEN_CODE = #{req.butenCode}
AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber})
AND (B.NAME_KANJI = #{req.customerNameKanjiKana} OR B.NAME_KANA = #{req.customerNameKanjiKana})
AND (B.NAME_KANJI like CONCAT(#{req.customerNameKanjiKana}, '%') OR B.NAME_KANA like CONCAT(#{req.customerNameKanjiKana}, '%'))
AND (B.NAME_KANJI like CONCAT(CONCAT('%', #{req.customerNameKanjiKana}), '%') OR B.NAME_KANA like CONCAT(CONCAT('%', #{req.customerNameKanjiKana}), '%'))
AND (TRIM(A.BRAND_CD) = #{req.brandCode} OR A.BRAND_CD = '0' || #{req.brandCode})
AND B.CUSTOMER_ATTRIBUTE IN
#{course}
AND (A.ACCEPT_DATE >= #{req.periodYmFrom} AND A.ACCEPT_DATE <= #{req.periodYmTo})
ORDER BY A.BROKER_CODE ASC, A.BUTEN_CODE ASC, A.ACCOUNT_NUMBER ASC, A.IFA_ORDER_NO DESC, A.IFA_ORDER_SUB_NO ASC

