irmItemFukusu, A.DOUITSU_TUKA_KUNI_KBN AS douitsuTukaKuniKbn, A.TASHA_NORIKAE_KBN AS tashaNorikaeKbn, A.TANKI_SELL_KBN AS tankiSellKbn, A.SHOKAN_MAE_KBN AS shokanMaeKbn, H.USER_NM AS userName, A.BROKER_CODE AS brokerCode, D.BRANCH_NAME AS brokerName, E.BROKER_BRANCH_CODE AS brokerageBranchCode, E.BRANCH_NAME AS brokerBranchName, A.INTERMEDIARY_EMP_CD AS brokerChargeCode, E.BROKER_CHARGE_NAME AS employeeName, G.VISIBLE_BUTEN_CODE AS viewAblrButenCode, A.ORDER_TYPE AS orderType, A.TRADE_KBN AS tradeKbn, A.ORDER_DATE as orderPlacementDate, A.SPECIFIC_KBN as specificAccountType FROM JP_TOUSHIN_ORDER A INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO B ON A.BUTEN_CODE = B.BUTEN_CODE AND A.ACCOUNT_NUMBER = B.ACCOUNT_NUMBER AND ( (TRIM(A.SHUBETU) IS NULL AND A.SHUBETU IS NOT NULL) OR (TRIM(A.SHUBETU) = 'APL' AND A.CODE LIKE 'W%') ) LEFT JOIN FUND C ON C.M_F_NRICODE = CONCAT(CONCAT(A.FUND_CD_KAISU,FUND_CD_GOU),' ') AND C.M_F_TYPE IN ('1', '2') AND C.M_F_DELFLG = '0' LEFT JOIN MEDIATE_BRANCH D ON A.BROKER_CODE = D.BROKER_CODE AND D.BROKER_BRANCH_KIND = '00' AND D.DELETE_FLG = '0' LEFT JOIN mediateChargeInfoAvailable E ON A.BROKER_CODE = E.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = E.BROKER_CHARGE_CODE LEFT JOIN SUB_DEALER_CODE_RELATION_IFAP G ON A.BUTEN_CODE = G.BUTEN_CODE AND A.ACCOUNT_NUMBER = G.ACCOUNT_NUMBER LEFT JOIN TB_MED_USERS H ON A.CREATE_USER = H.USER_ID
