WITH mediateChargeInfoAvailable AS ( SELECT DISTINCT /*+ INDEX(MEDIATE_CHARGE_INFO MEDIATE_CHARGE_INFO_IN1) */ MCI.BROKER_CODE , CASE B.CNT WHEN 1 THEN MCI.BROKER_BRANCH_CODE ELSE '' END AS BROKER_BRANCH_CODE , CASE B.CNT WHEN 1 THEN MB.BRANCH_NAME ELSE '' END AS BRANCH_NAME , MCI.BROKER_CHARGE_CODE , CASE MCI.BROKER_CHARGE_CODE WHEN '0000' THEN '' ELSE MCI.BROKER_CHARGE_NAME END AS BROKER_CHARGE_NAME FROM MEDIATE_CHARGE_INFO MCI INNER JOIN ( SELECT BROKER_CODE , BROKER_CHARGE_CODE , COUNT(*) CNT FROM MEDIATE_CHARGE_INFO WHERE DELETE_FLG = '0' GROUP BY BROKER_CODE , BROKER_CHARGE_CODE ) B ON MCI.BROKER_CODE = B.BROKER_CODE AND MCI.BROKER_CHARGE_CODE = B.BROKER_CHARGE_CODE LEFT OUTER JOIN MEDIATE_BRANCH MB ON MCI.BROKER_CODE = MB.BROKER_CODE AND MCI.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE WHERE MCI.DELETE_FLG = '0' GROUP BY MCI.BROKER_CODE , MCI.BROKER_BRANCH_CODE , MB.BRANCH_NAME , MCI.BROKER_CHARGE_CODE , BROKER_CHARGE_NAME , B.CNT ) SELECT /* @SQLID=SUB020302_0101-01#Sql003 */ COUNT(*) OVER() AS totalCount, A.BUTEN_CODE AS buten, A.ACCOUNT_NUMBER AS accountNumber, B.CUSTOMER_ATTRIBUTE AS customerAttribute, B.NAME_KANJI AS customerNameKanji, B.NAME_KANA AS customerNameKana, A.PRODUCT_CODE AS brandCode, C.BB_PRODUCT_NAME AS brandName, J.ORDER_STATUS AS orderStatus, J.DEPOSIT_TYPE AS depositType, J.ORDER_TIME AS recruitmentOrderDate, J.ORDER_COUNT AS quantity, A.ORDER_PRICE AS issueBbPrice, J.INVITATION_TYPE AS kanyuKbn, J.ORDER_METHOD AS orderMethod, J.EXPLANATION_INFO AS mostImportantMatter, J.WARNING_APPLY AS warningApplyArranged, J.PROSPECTUS AS prospectus, H.USER_NM AS userName, A.BROKER_CODE AS brokerCode, D.BRANCH_NAME AS brokerName, E.BROKER_BRANCH_CODE AS brokerageBranchCode, E.BRANCH_NAME AS brokerBranchName, A.INTERMEDIARY_EMP_CD AS brokerChargeCode, E.BROKER_CHARGE_NAME AS employeeName, G.VISIBLE_BUTEN_CODE AS viewAblrButenCode FROM T_IPO_PO_ORDER A INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO B ON A.BUTEN_CODE = B.BUTEN_CODE AND A.ACCOUNT_NUMBER = B.ACCOUNT_NUMBER INNER JOIN M_IPO_PO_BB_PERIOD I ON A.PRODUCT_CODE = I.PRODUCT_CODE AND A.PRESENTATION_FROM = I.PRESENTATION_FROM INNER JOIN T_IPO_PO_ORDER_DETAIL J ON A.PRODUCT_CODE = J.PRODUCT_CODE AND A.PRESENTATION_FROM = J.PRESENTATION_FROM AND A.BUTEN_CODE = J.BUTEN_CODE AND A.ACCOUNT_NUMBER = J.ACCOUNT_NUMBER AND J.ORDER_STATUS <> '0' LEFT JOIN BB_PRODUCT_MASTER C ON A.PRODUCT_CODE = C.BB_PRODUCT_CODE AND A.PRESENTATION_FROM = TO_NUMBER(TO_CHAR(C.BB_PRESENTATION_FROM, 'YYYYMMDD')) LEFT JOIN MEDIATE_BRANCH D ON A.BROKER_CODE = D.BROKER_CODE AND D.BROKER_BRANCH_KIND = '00' AND D.DELETE_FLG = '0' LEFT JOIN mediateChargeInfoAvailable E ON A.BROKER_CODE = E.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = E.BROKER_CHARGE_CODE LEFT JOIN SUB_DEALER_CODE_RELATION_IFAP G ON A.BUTEN_CODE = G.BUTEN_CODE AND A.ACCOUNT_NUMBER = G.ACCOUNT_NUMBER LEFT JOIN TB_MED_USERS H ON J.ORDER_USER = H.USER_ID
I.PRESENTATION_DATE >= IFA_DATE_UTIL.IFA_GET_SDATE('yyyyMMdd')
