WITH mediateChargeInfoAvailable AS ( SELECT DISTINCT /*+ INDEX(MEDIATE_CHARGE_INFO MEDIATE_CHARGE_INFO_IN1) */ MCI.BROKER_CODE , CASE B.CNT WHEN 1 THEN MCI.BROKER_BRANCH_CODE ELSE '' END AS BROKER_BRANCH_CODE , CASE B.CNT WHEN 1 THEN MB.BRANCH_NAME ELSE '' END AS BRANCH_NAME , MCI.BROKER_CHARGE_CODE , CASE MCI.BROKER_CHARGE_CODE WHEN '0000' THEN '' ELSE MCI.BROKER_CHARGE_NAME END AS BROKER_CHARGE_NAME FROM MEDIATE_CHARGE_INFO MCI INNER JOIN ( SELECT BROKER_CODE , BROKER_CHARGE_CODE , COUNT(*) CNT FROM MEDIATE_CHARGE_INFO WHERE DELETE_FLG = '0' GROUP BY BROKER_CODE , BROKER_CHARGE_CODE ) B ON MCI.BROKER_CODE = B.BROKER_CODE AND MCI.BROKER_CHARGE_CODE = B.BROKER_CHARGE_CODE LEFT OUTER JOIN MEDIATE_BRANCH MB ON MCI.BROKER_CODE = MB.BROKER_CODE AND MCI.BROKER_BRANCH_CODE = MB.BROKER_BRANCH_CODE WHERE MCI.DELETE_FLG = '0' GROUP BY MCI.BROKER_CODE , MCI.BROKER_BRANCH_CODE , MB.BRANCH_NAME , MCI.BROKER_CHARGE_CODE , BROKER_CHARGE_NAME , B.CNT ) SELECT /* @SQLID=SUB020302_0101-01#Sql004 */ COUNT(*) OVER() AS totalCount, A.BUTEN_CODE AS butenCode, A.ACCOUNT_NUMBER AS accountNumber, B.CUSTOMER_ATTRIBUTE AS customerAttribute, B.NAME_KANJI AS customerNameKanji, B.NAME_KANA AS customerNameKana, A.ACCEPT_ORDER_NO AS acceptOrderNumber, A.ACCEPT_ORDER_SUB_NO AS acceptOrderSubNumber, A.BRAND_CODE AS tickerCode, A.BRAND_NAME AS brandName, A.EXCHANGE_CODE AS marketCode, A.ORDER_TYPE AS securiytClassType, A.METHOD_TYPE AS methodType, A.TRADE_TYPE AS tradeKbn, A.TRADE_METHOD_TYPE AS priceConditionsType, A.STOP_PRICE AS stopOrderPrice, A.SETTLEMENT_TYPE AS settlementType, A.DEPOSIT_TYPE AS depositType, A.ORDER_TIME AS orderTime, A.TRADE_LIMIT_DATE AS orderDeadlineDate, A.ORDER_QUANTITY AS orderQuantity, A.LIMIT_PRICE AS sashine, A.CURRENCY_CODE AS currencyCode, A.INVITATION_TYPE AS kanyuKbn, A.ORDER_METHOD_TYPE AS jutyuKbn, A.ENG_PUB_BRAND_EXP_TYPE AS engPubType, A.EXPLANATION_INFO_TYPE AS importantMatterTypeClass, A.WARNING_APPLY_TYPE AS warningApplyTrade, A.TRANSFER_INVITATION_TYPE AS solicitationEtfType, G.USER_NM AS userName, A.BROKER_CODE AS brokerCode, C.BRANCH_NAME AS brokerName, D.BROKER_BRANCH_CODE AS brokerageBranchCode, D.BRANCH_NAME AS brokerBranchName, A.INTERMEDIARY_EMP_CD AS brokerChargeCode, D.BROKER_CHARGE_NAME AS employeeName, F.VISIBLE_BUTEN_CODE AS viewAblrButenCode FROM FOREIGN_CONSIGNMENT_ORDER A INNER JOIN MEDIATE_USER_ATTRIBUTE_INFO B ON A.BUTEN_CODE = B.BUTEN_CODE AND A.ACCOUNT_NUMBER = B.ACCOUNT_NUMBER AND A.API_STATUS_CODE BETWEEN 200 AND 299 LEFT JOIN MEDIATE_BRANCH C ON A.BROKER_CODE = C.BROKER_CODE AND C.BROKER_BRANCH_KIND = '00' AND C.DELETE_FLG = '0' LEFT JOIN mediateChargeInfoAvailable D ON A.BROKER_CODE = D.BROKER_CODE AND A.INTERMEDIARY_EMP_CD = D.BROKER_CHARGE_CODE LEFT JOIN SUB_DEALER_CODE_RELATION_IFAP F ON A.BUTEN_CODE = F.BUTEN_CODE AND A.ACCOUNT_NUMBER = F.ACCOUNT_NUMBER LEFT JOIN TB_MED_USERS G ON A.CREATE_USER = G.USER_ID
