P G ON A.BUTEN_CODE = G.BUTEN_CODE AND TO_NUMBER(TRIM(A.ACCOUNT_NUMBER)) = G.ACCOUNT_NUMBER LEFT JOIN TB_MED_USERS H ON A.CREATE_USER = H.USER_ID
